// // This module implements a register with active-high reset and disable signals. When RESET_A is high, the output Q is reset to 1. If RESET_A is low and the disable signal (DIS) is deasserted, the output Q is assigned the value of D if SEL is low; otherwise, Q is assigned the logical negation of D.
module top_module(
    input  D      ,
    output Q      ,
    input  RESET_B,
    input  CLK    ,
    input  EN     ,
    input  SEL
);reg Q_reg;

    always @(posedge CLK) begin
        if (RESET_B == 0) begin
            Q_reg <= 0;
        end else if (EN == 1) begin
            if (SEL == 1) begin
                Q_reg <= D;
            end else begin
                Q_reg <= ~D;
            end
        end
    end

    assign Q = Q_reg;

endmodule
